+function sanitizeIPs(text) {
+  return text.replace(/\b(?!10\.|172\.(1[6-9]|2\d|3[01])\.|192\.168\.|127\.|0\.0\.0\.)(\d{1,3}\.){3}\d{1,3}\b/g, '192.0.2.1')
